    #[test]
    fn test_create_scheduled_transaction_rejects_max_priority_fee_overflow() {
        let _ = SynchronousScheduler::initialize(Address::ZERO);

        let call = make_call(U256::from(20_000_000_000u64), U256::MAX); // 20 gwei max, overflow priority
        let result = create_scheduled_transaction(1, call, 100, 0, B256::ZERO);
        assert!(result.is_err(), "Expected Err for max_priority_fee_per_gas=U256::MAX");
        let err = result.unwrap_err();
        assert!(
            err.to_string().contains("out-of-range fee fields"),
            "Expected overflow message, got: {}",
            err
        );
    }
